[sample data sets](available-sample-datasets). After you
[Load Sample Data Into Atlas](load-sample-data), you can use
these examples to index fields as the dateFacet type.Basic ExampleThe following example index definition indexes the  `released`
field as the MongoDB Search `date` type to support queries against that
field using MongoDB Search operators such as [near](near-ref),
[range](range-ref), and [equals](equals-ref).```go
package main

import (
	"context"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()

	// Retrieves your Atlas connection string
	const uri = "<connection-string>"

	// Connect to your Atlas cluster
	clientOptions := options.Client().ApplyURI(uri)
	client, err := mongo.Connect(clientOptions)
	if err != nil {
		log.Fatalf("Failed to connect to the server: %v", err)
	}
	defer func() {
		if err := client.Disconnect(ctx); err != nil {
			log.Fatalf("Failed to disconnect: %v", err)
		}
	}()

	// Set the namespace
	coll := client.Database("sample_mflix").Collection("movies")
	opts := options.SearchIndexes().SetName("default")

	// Define your search index
	index := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"released", bson.D{
						{"type", "date"},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	result, err := coll.SearchIndexes().CreateOne(ctx, index)
	if err != nil {
		log.Fatalf("Failed to create search index: %v", err)
	}
	log.Printf("New index name: %v", result)
}

